import React from 'react';
import Dialog from './Dialog/Dialog';
import Mass from './Mass/Mass';
import s from './NavMassage.module.css'

const NavMassage = (props) => {


    let dialogsElement =
        props.dialogs.map(d => <Dialog name={d.name} id={d.id} />);

    let messagesElement =
        props.messages.map(m => <Mass message={m.message} />);
    return (
        <div className={s.navmassage} >
            <div className={s.dialog}>
                {dialogsElement}
            </div>
            <div>
                {messagesElement}
            </div>
        </div>
    )
}
export default NavMassage;
